SELECT bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade = 0 AND bs.state = 'CO' AND (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state) IN (SELECT up.bldg_id, up."in.nhgis_tract_gisjoin", up.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up WHERE up.upgrade IN (2) AND up.applicability = true GROUP BY up.bldg_id, up."in.nhgis_tract_gisjoin", up.state HAVING count(distinct(up.upgrade)) = 1)